import anthropic

client = anthropic.Anthropic()


def beam_search(
    problem: str,
    branching: int = 3,
    beam_width: int = 2,
    max_depth: int = 3,
) -> list[str]:
    """BFS beam search: at each depth keep only the top `beam_width` paths."""

    # Each beam entry is (path_as_list, cumulative_score)
    beam: list[tuple[list[str], float]] = [([],  0.0)]

    for depth in range(max_depth):
        candidates: list[tuple[list[str], float]] = []

        for path, cum_score in beam:
            context = " → ".join(path) if path else "(start)"
            resp = client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=300,
                temperature=0.7,
                messages=[{
                    "role": "user",
                    "content": (
                        f"Problem: {problem}\n"
                        f"Path: {context}\n"
                        f"List {branching} candidate next steps, numbered."
                    ),
                }],
            ).content[0].text.strip()

            thoughts = [
                l.strip().lstrip("0123456789.-) ")
                for l in resp.splitlines() if l.strip()
            ][:branching]

            for t in thoughts:
                score_resp = client.messages.create(
                    model="claude-haiku-4-5-20251001",
                    max_tokens=10,
                    temperature=0.0,
                    messages=[{
                        "role": "user",
                        "content": (
                            f"Problem: {problem}\nPath: {context} → {t}\n"
                            "Score 0–10. Reply with the number only."
                        ),
                    }],
                ).content[0].text.strip()
                try:
                    score = float(score_resp.split()[0])
                except (ValueError, IndexError):
                    score = 5.0
                candidates.append((path + [t], cum_score + score))

        # Keep top beam_width by cumulative score
        beam = sorted(candidates, key=lambda x: x[1], reverse=True)[:beam_width]
        print(f"Depth {depth+1}: top beam score = {beam[0][1]:.1f}")

    return beam[0][0]  # return the highest-scored complete path


problem = "Describe a 3-step approach to debugging a memory leak in a Python application."
path = beam_search(problem, branching=3, beam_width=2, max_depth=3)
print("\nSelected path:")
for i, step in enumerate(path, 1):
    print(f"  {i}. {step}")

import anthropic
import re

client = anthropic.Anthropic()


def generate_next_expressions(numbers: list[float], depth: int, n: int = 3) -> list[str]:
    """Generate candidate next expressions combining two of the remaining numbers."""
    nums_str = ", ".join(str(int(x) if x == int(x) else x) for x in numbers)
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=200,
        temperature=0.8,
        messages=[{
            "role": "user",
            "content": (
                f"Numbers available: {nums_str}\n"
                f"Goal: reach 24 using each number exactly once with +, -, *, /.\n"
                f"List {n} distinct ways to combine any two of these numbers into a new number, "
                "one per line. Format: 'a op b = c (remaining: r1, r2, ...)'"
            ),
        }],
    ).content[0].text.strip()
    lines = [l.strip() for l in resp.splitlines() if l.strip()]
    return lines[:n]


def evaluate_state(numbers: list[float]) -> float:
    """Ask the model to rate whether the current numbers can reach 24."""
    nums_str = ", ".join(str(int(x) if x == int(x) else x) for x in numbers)
    if len(numbers) == 1:
        return 10.0 if abs(numbers[0] - 24) < 1e-6 else 0.0
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=10,
        temperature=0.0,
        messages=[{
            "role": "user",
            "content": (
                f"Numbers: {nums_str}. Can these reach 24 with +,-,*,/? "
                "Rate 0 (impossible) to 10 (definitely reachable). Reply with number only."
            ),
        }],
    ).content[0].text.strip()
    try:
        return float(resp.split()[0])
    except (ValueError, IndexError):
        return 5.0


def parse_result(line: str) -> tuple[list[float], str] | None:
    """Extract the remaining numbers after a step."""
    m = re.search(r"remaining:\s*([0-9.,\s]+)", line, re.IGNORECASE)
    if not m:
        return None
    try:
        nums = [float(x.strip()) for x in m.group(1).split(",") if x.strip()]
        return nums, line
    except ValueError:
        return None


def tot_game24(start: list[int], beam_width: int = 2, max_depth: int = 3) -> str | None:
    beam = [(list(map(float, start)), [], 0.0)]   # (numbers, steps, score)

    for depth in range(max_depth):
        candidates = []
        for numbers, steps, cum_score in beam:
            exprs = generate_next_expressions(numbers, depth)
            for expr in exprs:
                parsed = parse_result(expr)
                if parsed is None:
                    continue
                remaining, step_text = parsed
                score = evaluate_state(remaining)
                candidates.append((remaining, steps + [step_text], cum_score + score))

        candidates.sort(key=lambda x: x[2], reverse=True)
        beam = candidates[:beam_width]
        print(f"Depth {depth+1}: best score={beam[0][2]:.1f} | {beam[0][1][-1][:60]}")

    # Check if any beam member reached 24
    for nums, steps, score in beam:
        if len(nums) == 1 and abs(nums[0] - 24) < 1e-6:
            return "\n".join(steps)

    return beam[0][1][-1] if beam else None


result = tot_game24([4, 8, 6, 3], beam_width=2, max_depth=3)
print("\nBest path found:")
print(result)
